<?php namespace App\Services\Market; use App\Models\Market\MarketPlanning; use App\Models\Market\MarketReport; class MarketIntelligenceService { public function createPlanning($data) { return MarketPlanning::create([...$data, 'created_by' => auth()->id()]); } public function approvePlanning(MarketPlanning $planning, $remarks) { $planning->update(['vetting_status' => 'VETTED', 'vetted_by' => auth()->id(), 'vetted_at' => now(), 'vetting_remarks' => $remarks]); } public function createReport($data) { return MarketReport::create([...$data, 'created_by' => auth()->id()]); } }
